package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;
import org.mockito.Mockito;
import static org.mockito.Mockito.when;

import java.lang.reflect.Constructor;

public class CSVFormatTest {

    @Test
    public void testGetIgnoreSurroundingSpaces() throws Exception {
        // Given
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                Character.class, Character.class, boolean.class, boolean.class, String.class, String.class,
                Object[].class, String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat csvFormat = constructor.newInstance(',', '"', null, null, null, true, false, "\r\n",
                null, null, null, false, false, false, false, false);

        // When
        boolean result = csvFormat.getIgnoreSurroundingSpaces();

        // Then
        assertEquals(true, result);
    }

    @Test
    public void testGetIgnoreSurroundingSpacesWithMock() throws Exception {
        // Given
        Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                Character.class, Character.class, boolean.class, boolean.class, String.class, String.class,
                Object[].class, String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat csvFormat = constructor.newInstance(',', '"', null, null, null, true, false, "\r\n",
                null, null, null, false, false, false, false, false);
        CSVFormat spyFormat = Mockito.spy(csvFormat);
        when(spyFormat.getIgnoreSurroundingSpaces()).thenReturn(true);

        // When
        boolean result = spyFormat.getIgnoreSurroundingSpaces();

        // Then
        assertEquals(true, result);
    }
}
